+    /// Create a test renderer with all terminal options disabled.
+    fn test_renderer(width: u32, height: u32) -> Renderer {
+        Renderer::new_with_options(
+            width,
+            height,
+            RendererOptions {
+                use_alt_screen: false,
+                hide_cursor: false,
+                enable_mouse: false,
+                query_capabilities: false,
